# 5. 时间线编辑器：页面内编辑

第一版先存在浏览器本地，后续再接 GitHub API / Decap / Tina。

```tsx
import { useEffect, useState } from "react";

type TimelineItem = {
  id: string;
  date: string;
  title: string;
  body: string;
  author: string;
};

export default function ProjectTimelineEditor({ projectSlug }: { projectSlug: string }) {
  const key = `project:${projectSlug}:timeline`;

  const [items, setItems] = useState<TimelineItem[]>([]);
  const [title, setTitle] = useState("");
  const [body, setBody] = useState("");

  useEffect(() => {
    try {
      setItems(JSON.parse(localStorage.getItem(key) || "[]"));
    } catch {
      setItems([]);
    }
  }, [key]);

  function save(next: TimelineItem[]) {
    setItems(next);
    localStorage.setItem(key, JSON.stringify(next));
  }

  function addItem() {
    if (!title.trim()) return;

    save([
      {
        id: crypto.randomUUID(),
        date: new Date().toISOString().slice(0, 10),
        title: title.trim(),
        body: body.trim(),
        author: "本地编辑"
      },
      ...items
    ]);

    setTitle("");
    setBody("");
  }

  return (
    <div className="timeline-editor">
      <div className="timeline-compose">
        <input
          value={title}
          onChange={(event) => setTitle(event.target.value)}
          placeholder="记录今天的进展..."
        />
        <textarea
          value={body}
          onChange={(event) => setBody(event.target.value)}
          placeholder="补充说明，可写世界观、模块变更、卡牌调整..."
        />
        <button onClick={addItem}>发布进展</button>
      </div>

      <div className="timeline-list">
        {items.length === 0 ? (
          <p className="timeline-empty">暂无时间线记录。</p>
        ) : (
          items.map((item) => (
            <article className="timeline-item" key={item.id}>
              <time>{item.date}</time>
              <strong>{item.title}</strong>
              {item.body ? <p>{item.body}</p> : null}
              <span>{item.author}</span>
            </article>
          ))
        )}
      </div>
    </div>
  );
}
```

